
import * as UCNowTime from '@/components/UCNowTime'
import * as UCRandomBG from '@/components/UCRandomBG'
import { BroswerType } from '@/components/UCBrowserType'
import { onMounted, ref } from 'vue'

export default {
	name: 'Home',
	setup() {
		const enter = (url: string) => {
			window.open(url)
		}

		const bt = ref({})
		const nowTime = UCNowTime.nowTime
		const getNow = UCNowTime.getNow

		onMounted(() => {
			UCRandomBG.RBGconfig(getNow())
			UCRandomBG.RBG()
			bt.value = BroswerType()
			console.log(bt.value)
		})
		return {
			bt,
			enter,
			nowTime,
			getNow,
		}
	},
}
